node <<'EOF'
const ids=['CVE-2017-16042','CVE-2017-16011','CVE-2017-16026','CVE-2020-26289','CVE-2020-36632','CVE-2021-23337','CVE-2021-32803','CVE-2018-16469'];
(async()=>{
  for(const id of ids){
    try{
      const r=await fetch('https://api.osv.dev/v1/vulns/'+id);
      if(!r.ok){console.log(id,'HTTP',r.status); continue;}
      const j=await r.json();
      const npm=(j.affected||[]).filter(a=>a.package&&a.package.ecosystem==='npm');
      let hasFixed=false;
      for(const a of npm){
        for(const rg of (a.ranges||[])){
          for(const ev of (rg.events||[])){
            if(ev.fixed) hasFixed=true;
          }
        }
      }
      console.log(id,'npmPkgs=',npm.length,'hasFixed=',hasFixed);
    }catch(e){
      console.log(id,'ERR',e.message);
    }
  }
})();
EOF
